'use strict';

const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.PAYMENT_QUEUE || 'payment_events';
const PREFETCH = Number(process.env.PREFETCH || 10);

async function chargePayment(payment) {
  console.log('Charging payment', {
    userId: payment.userId,
    amount: payment.amount,
    currency: payment.currency,
    paymentMethodId: payment.paymentMethodId,
    orderId: payment.orderId,
  });

  await new Promise((resolve) => setTimeout(resolve, 300));

  return {
    success: true,
    transactionId: `txn_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`,
  };
}

async function refundPayment(payment) {
  console.log('Refunding payment', {
    transactionId: payment.transactionId,
    amount: payment.amount,
    reason: payment.reason,
    orderId: payment.orderId,
  });

  await new Promise((resolve) => setTimeout(resolve, 300));

  return {
    success: true,
    refundId: `ref_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`,
  };
}

async function processPaymentEvent(event) {
  switch (event.type) {
    case 'payment.charge':
      return chargePayment(event.data);
    case 'payment.refund':
      return refundPayment(event.data);
    default:
      throw new Error(`Unsupported payment event type: ${event.type}`);
  }
}

async function startConsumer() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  await channel.assertQueue(QUEUE_NAME, { durable: true });
  await channel.prefetch(PREFETCH);

  console.log(`Waiting for messages on queue: ${QUEUE_NAME}`);

  channel.consume(
    QUEUE_NAME,
    async (msg) => {
      if (!msg) return;

      try {
        const raw = msg.content.toString('utf8');
        const event = JSON.parse(raw);

        console.log('Received payment event', {
          type: event.type,
          id: event.id,
          receivedAt: new Date().toISOString(),
        });

        const result = await processPaymentEvent(event);

        console.log('Payment event processed successfully', {
          eventId: event.id,
          type: event.type,
          result,
        });

        channel.ack(msg);
      } catch (error) {
        console.error('Failed to process payment event', {
          error: error.message,
          stack: error.stack,
        });

        channel.nack(msg, false, false);
      }
    },
    { noAck: false }
  );

  const shutdown = async () => {
    console.log('Shutting down consumer...');
    try {
      await channel.close();
    } catch (_) {}
    try {
      await connection.close();
    } catch (_) {}
    process.exit(0);
  };

  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);
}

startConsumer().catch((error) => {
  console.error('Consumer startup failed', error);
  process.exit(1);
});